{
    "level": "B1",
    "intro": "In this topic, you will learn how to use <strong>passive with modal verbs</strong>: can, could, may, might, must, should, will, would. The formula is simple: <strong>modal + be + V3</strong>.",
    "rules": [
        {
            "label": "Formula",
            "color": "emerald",
            "text": "<strong>Subject + modal + be + V3</strong>:",
            "example": "This task must be done today."
        },
        {
            "label": "Denial",
            "color": "rose",
            "text": "<strong>Subject + modal + not + be + V3</strong>:",
            "example": "This task cannot be done today."
        },
        {
            "label": "Question",
            "color": "blue",
            "text": "<strong>Modal + Subject + be + V3?</strong>:",
            "example": "Can this task be done today?"
        }
    ]
}

{
    "title": "1. Modal verbs in the passive",
    "intro": "Formula: <strong>modal + be + V3</strong>:",
    "items": [
        {
            "label": "can",
            "title": "can be done",
            "subtitle": "This can be fixed. - This can be fixed."
        },
        {
            "label": "could",
            "title": "could be done",
            "subtitle": "It could be improved. — It could be improved."
        },
        {
            "label": "may",
            "title": "may be done",
            "subtitle": "It may be postponed. - It can be postponed."
        },
        {
            "label": "might",
            "title": "might be done",
            "subtitle": "It might be canceled. - This can be canceled."
        },
        {
            "label": "must",
            "title": "must be done",
            "subtitle": "It must be finished. - This must be completed."
        },
        {
            "label": "should",
            "title": "should be done",
            "subtitle": "It should be checked. — It's worth checking."
        },
        {
            "label": "will",
            "title": "will be done",
            "subtitle": "It will be completed. - It will be completed."
        },
        {
            "label": "would",
            "title": "would be done",
            "subtitle": "It would be appreciated. - That would be appreciated."
        }
    ]
}

{
    "title": "2. The meaning of modal verbs in the passive",
    "sections": [
        {
            "label": "can / could — possibility",
            "color": "emerald",
            "description": "<strong>Opportunity</strong> or <strong>ability</strong>:",
            "examples": [
                {
                    "en": "The problem can be solved easily.",
                    "ua": "The problem can be solved easily."
                },
                {
                    "en": "This could be done in a different way.",
                    "ua": "This could be done in a different way."
                },
                {
                    "en": "The document can be downloaded online.",
                    "ua": "The document can be downloaded online."
                }
            ]
        },
        {
            "label": "may / might — probability",
            "color": "blue",
            "description": "<strong>Probability</strong> or <strong>permit</strong>:",
            "examples": [
                {
                    "en": "The meeting may be postponed.",
                    "ua": "The meeting may be postponed."
                },
                {
                    "en": "The flight might be cancelled.",
                    "ua": "The flight might be cancelled."
                },
                {
                    "en": "Photos may be taken here.",
                    "ua": "Photos may be taken here."
                }
            ]
        },
        {
            "label": "must / have to — necessity",
            "color": "amber",
            "description": "<strong>Necessity</strong> or <strong>obligation</strong>:",
            "examples": [
                {
                    "en": "This work must be done today.",
                    "ua": "This work must be done today."
                },
                {
                    "en": "The rules must be followed.",
                    "ua": "The rules must be followed."
                },
                {
                    "en": "Taxes have to be paid on time.",
                    "ua": "Taxes have to be paid on time."
                }
            ]
        },
        {
            "label": "should / ought to — recommendation",
            "color": "rose",
            "description": "<strong>Recommendation</strong> or <strong>advice</strong>:",
            "examples": [
                {
                    "en": "The report should be checked carefully.",
                    "ua": "The report should be checked carefully."
                },
                {
                    "en": "Children should be protected.",
                    "ua": "Children should be protected."
                },
                {
                    "en": "This information ought to be verified.",
                    "ua": "This information ought to be verified."
                }
            ]
        }
    ]
}

{
    "title": "3. Objections with modal verbs",
    "sections": [
        {
            "label": "cannot / can't be done",
            "color": "rose",
            "description": "<strong>Impossibility</strong>:",
            "examples": [
                {
                    "en": "This problem cannot be solved.",
                    "ua": "This problem cannot be solved."
                },
                {
                    "en": "The deadline can't be extended.",
                    "ua": "The deadline can't be extended."
                }
            ]
        },
        {
            "label": "must not / mustn't be done",
            "color": "amber",
            "description": "<strong>Prohibition</strong>:",
            "examples": [
                {
                    "en": "This information must not be shared.",
                    "ua": "This information must not be shared."
                },
                {
                    "en": "The password mustn't be revealed.",
                    "ua": "The password mustn't be revealed."
                }
            ]
        },
        {
            "label": "should not / shouldn't be done",
            "color": "sky",
            "description": "<strong>Not recommended</strong>:",
            "examples": [
                {
                    "en": "This shouldn't be ignored.",
                    "ua": "This shouldn't be ignored."
                },
                {
                    "en": "Children should not be left alone.",
                    "ua": "Children should not be left alone."
                }
            ]
        }
    ]
}

{
    "title": "4. Questions with modal verbs",
    "sections": [
        {
            "label": "Yes/No question",
            "color": "blue",
            "description": "<strong>Modal + Subject + be + V3?</strong>:",
            "examples": [
                {
                    "en": "Can this be done today?",
                    "ua": "Can this be done today?"
                },
                {
                    "en": "Should the report be submitted now?",
                    "ua": "Should the report be submitted now?"
                },
                {
                    "en": "Must the rules be followed?",
                    "ua": "Must the rules be followed?"
                }
            ]
        },
        {
            "label": "Wh question",
            "color": "emerald",
            "description": "<strong>Wh-word + modal + Subject + be + V3?</strong>:",
            "examples": [
                {
                    "en": "When can the work be finished?",
                    "ua": "When can the work be finished?"
                },
                {
                    "en": "How should the problem be solved?",
                    "ua": "How should the problem be solved?"
                },
                {
                    "en": "Where can the tickets be bought?",
                    "ua": "Where can the tickets be bought?"
                }
            ]
        }
    ]
}

{
    "title": "5. Comparison of Active vs Passive with modals",
    "intro": "How to turn an active sentence with a modal verb into a passive one:",
    "rows": [
        {
            "en": "Active: You must finish this work.",
            "ua": "Active: You must finish this work.",
            "note": "→ Passive: This work must be finished."
        },
        {
            "en": "Active: They can solve the problem.",
            "ua": "Active: They can solve the problem.",
            "note": "→ Passive: The problem can be solved."
        },
        {
            "en": "Active: You should check the report.",
            "ua": "Active: You should check the report.",
            "note": "→ Passive: The report should be checked."
        },
        {
            "en": "Active: We may postpone the meeting.",
            "ua": "Active: We may postpone the meeting.",
            "note": "→ Passive: The meeting may be postponed."
        }
    ],
    "warning": "📌 The modal verb remains unchanged, only the main verb changes!"
}

{
    "title": "6. Perfect modals in the passive (about the past)",
    "intro": "Formula: <strong>modal + have been + V3</strong>:",
    "items": [
        {
            "label": "must have been",
            "title": "must have been done",
            "subtitle": "It must have been stolen. - It must have been stolen."
        },
        {
            "label": "should have been",
            "title": "should have been done",
            "subtitle": "It should have been checked. - It should have been checked."
        },
        {
            "label": "could have been",
            "title": "could have been done",
            "subtitle": "It could have been avoided. - This could have been avoided."
        },
        {
            "label": "might have been",
            "title": "might have been done",
            "subtitle": "It might have been lost. - Maybe they lost it."
        }
    ]
}

{
    "title": "7. Perfect modals in the passive: examples",
    "sections": [
        {
            "label": "Assumptions about the past",
            "color": "emerald",
            "description": "<strong>must/may/might/could have been + V3</strong>:",
            "examples": [
                {
                    "en": "The letter must have been sent yesterday.",
                    "ua": "The letter must have been sent yesterday."
                },
                {
                    "en": "The window may have been broken by the kids.",
                    "ua": "The window may have been broken by the kids."
                },
                {
                    "en": "The file might have been deleted accidentally.",
                    "ua": "The file might have been deleted accidentally."
                }
            ]
        },
        {
            "label": "Criticism of past action",
            "color": "rose",
            "description": "<strong>should have been + V3</strong> (should have been done, but not done):",
            "examples": [
                {
                    "en": "The report should have been submitted on time.",
                    "ua": "The report should have been submitted on time."
                },
                {
                    "en": "The problem should have been fixed earlier.",
                    "ua": "The problem should have been fixed earlier."
                },
                {
                    "en": "The warning should have been given.",
                    "ua": "The warning should have been given."
                }
            ]
        },
        {
            "label": "Unrealized opportunity",
            "color": "blue",
            "description": "<strong>could have been + V3</strong> (could have been done):",
            "examples": [
                {
                    "en": "The accident could have been avoided.",
                    "ua": "The accident could have been avoided."
                },
                {
                    "en": "The work could have been done faster.",
                    "ua": "The work could have been done faster."
                },
                {
                    "en": "The mistake could have been prevented.",
                    "ua": "The mistake could have been prevented."
                }
            ]
        }
    ]
}

{
    "title": "8. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Omission of be after a modal verb.",
            "wrong": "The work must done today.",
            "right": "✅ The work must be done today."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using to after a modal.",
            "wrong": "It can to be fixed.",
            "right": "✅ It can be fixed."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Incorrect form in Perfect.",
            "wrong": "It should have be done.",
            "right": "✅ It should have been done."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Changing the modal verb.",
            "wrong": "The work musts be done.",
            "right": "✅ The work must be done."
        }
    ]
}
